import{_ as e,o as t,c as o,O as i}from"./chunks/framework.bdcb0ee1.js";const p=JSON.parse('{"title":"Logging in to your admin panel","description":"","frontmatter":{},"headers":[],"relativePath":"administration/overview.md","filePath":"administration/overview.md","lastUpdated":1773167402000}'),a={name:"administration/overview.md"},n=i('<h1 id="logging-in-to-your-admin-panel" tabindex="-1">Logging in to your admin panel <a class="header-anchor" href="#logging-in-to-your-admin-panel" aria-label="Permalink to &quot;Logging in to your admin panel&quot;">​</a></h1><p>Managing your ForumSpark board is done through the Admin Control Panel (Admin CP) — a dedicated area where you can configure your board, manage content, and control user permissions.</p><h2 id="accessing-the-admin-cp" tabindex="-1">Accessing the Admin CP <a class="header-anchor" href="#accessing-the-admin-cp" aria-label="Permalink to &quot;Accessing the Admin CP&quot;">​</a></h2><p>To get started:</p><ol><li><strong>Log into the user account</strong> you created during forum registration.</li><li>In the top-right corner of the page, click on your username to open the user menu:</li></ol><img width="1951" height="414" alt="image" src="https://github.com/user-attachments/assets/1910d8ab-1fca-4eda-bb92-a91a50d0bab3"><ol start="3"><li>From the dropdown, click <strong>“Admin CP”</strong>.</li></ol><blockquote><p>💡 Only users with administrator permissions will see the Admin CP option.</p></blockquote><hr><p>Once inside the Admin CP, you&#39;ll land on the <strong>Admin Dashboard</strong>:</p><img width="1967" height="1832" alt="image" src="https://github.com/user-attachments/assets/fc322632-fb50-4acd-b0e5-d3a2fb339de5"><p>Here you’ll find:</p><ul><li><strong>Board Information</strong>: Forum owner, registration date, and transfer ownership link (if you&#39;re the board owner).</li><li><strong>Statistics</strong>: Quick overview of your board’s activity — member count, topic count, posts, and average posts per day.</li><li>Navigation links to configuration sections like: <ul><li>Board Settings</li><li>Domain Manager</li><li>Support Forum &amp; Changelog</li><li>Emoticons, Filters, Shoutbox, and more</li></ul></li></ul><h2 id="✅-next-steps" tabindex="-1">✅ Next Steps <a class="header-anchor" href="#✅-next-steps" aria-label="Permalink to &quot;✅ Next Steps&quot;">​</a></h2><p>From here, you can begin configuring your board:</p><ul><li>Update forum sections</li><li>Customize your board appearance</li><li>Moderate content and manage users</li></ul>',16),r=[n];function s(l,d,c,u,g,m){return t(),o("div",null,r)}const b=e(a,[["render",s]]);export{p as __pageData,b as default};
